
import { getNiveis, getConquistas, getDesafios } from '@/src/lib/supabase/queries/gamificacao';
import { GamificacaoClient } from './_components/GamificacaoClient';

export default async function AdminGamificacaoPage() {
    const [niveis, conquistas, desafios] = await Promise.all([
        getNiveis(),
        getConquistas(),
        getDesafios()
    ]);

    return (
        <GamificacaoClient
            niveis={niveis}
            conquistas={conquistas}
            desafios={desafios}
        />
    );
}
